import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';
import { TOOLTIP_CONTENT_PADDING, SCROLLBAR_WIDTH } from '../../constants.js';
import { useExternalConfig } from '../../contexts/ExternalConfigContext.js';
import { useDefaultLabels } from '../../hooks/useDefaultLabels.js';
import {
  seriesHeader,
  seriesHeaderName,
  seriesHeaderValue,
  seriesNameText,
  seriesValueText,
  TOOLTIP_MAX_WIDTH,
} from '../../tooltip.sty.js';
import { SeriesHeaderProps } from '../../types.js';
import { isValidNumber } from './utils/is-valid-number.js';
import { getHeaderTruncatedText } from '../../utils/text-truncation-header.js';

export const SeriesHeader = (props: SeriesHeaderProps) => {
  const { seriesLabel, valueLabel, disabled } = props;
  const { truncationMode } = useExternalConfig();
  const labelFor = useDefaultLabels();
  const maxWidth = (TOOLTIP_MAX_WIDTH - TOOLTIP_CONTENT_PADDING * 2) / 2;

  if (disabled || !labelFor || !isValidNumber(maxWidth)) {
    return null;
  }

  const seriesLabelText = labelFor('seriesLabel', seriesLabel) ?? '';
  const valueLabelText = labelFor('valueLabel', valueLabel) ?? '';

  const truncatedSeriesLabel = getHeaderTruncatedText(
    seriesLabelText,
    maxWidth,
    truncationMode,
  );
  const truncatedValueLabel = getHeaderTruncatedText(
    valueLabelText,
    maxWidth,
    truncationMode,
  );

  const isSeriesLabelTruncated = truncatedSeriesLabel !== seriesLabelText;
  const isValueLabelTruncated = truncatedValueLabel !== valueLabelText;

  return (
    <div
      className={seriesHeader}
      style={{
        maxWidth: `calc(100% - var(--needs-scrollbar-fix, 0) * ${SCROLLBAR_WIDTH}px)`,
      }}
    >
      <div className={seriesHeaderName}>
        <Tooltip text={seriesLabelText} disabled={!isSeriesLabelTruncated}>
          <span className={seriesNameText}>{truncatedSeriesLabel}</span>
        </Tooltip>
      </div>
      <div className={seriesHeaderValue}>
        <Tooltip text={valueLabelText} disabled={!isValueLabelTruncated}>
          <span className={seriesValueText}>{truncatedValueLabel}</span>
        </Tooltip>
      </div>
    </div>
  );
};
